const body = $json.body ?? {};
const lead = body.lead ?? {};
const errors = [];

if (!lead.name) errors.push('lead.name');
if (!lead.email) errors.push('lead.email');
if (lead.consent !== 'granted') errors.push('lead.consent');
if (!body.answers || typeof body.answers !== 'object') errors.push('answers');
if (!body.result || typeof body.result !== 'object') errors.push('result');

if (errors.length) {
  return [
    {
      json: {
        valid: false,
        statusCode: 400,
        responseBodyJson: JSON.stringify({
          ok: false,
          error: `Campos obrigatórios ausentes ou inválidos: ${errors.join(', ')}`
        })
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      body
    }
  }
];

function sqlText(value) {
  if (value === undefined || value === null || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlJson(value, fallback = {}) {
  const safeValue = value === undefined || value === null ? fallback : value;
  return `'${JSON.stringify(safeValue).replace(/'/g, "''")}'::jsonb`;
}

function sqlTimestamp(value) {
  if (!value) return 'now()';
  return `${sqlText(value)}::timestamptz`;
}

if (!$json.valid) {
  return [
    {
      json: {
        query: `select ${$json.statusCode} as status_code, ${sqlText($json.responseBodyJson)}::json as response_body;`
      }
    }
  ];
}

const body = $json.body;
const lead = body.lead ?? {};
const result = body.result ?? {};
const tracking = lead.tracking ?? body.tracking ?? {};
const legalNoticeVersion = lead.legalNoticeVersion ?? body.legalNoticeVersion ?? null;

const query = `
with inserted as (
  insert into entrepreneur_profile_results (
    created_at,
    lead_name,
    lead_email,
    lead_phone,
    lead_consent,
    lead_consent_timestamp,
    legal_notice_version,
    dominant_operational,
    dominant_motivation,
    dominant_behavior,
    lowest_behavior,
    composite,
    result_title,
    cta_label,
    cta_href,
    answers_json,
    tracking_json,
    raw_payload_json
  ) values (
    ${sqlTimestamp(body.createdAt)},
    ${sqlText(lead.name)},
    ${sqlText(lead.email)},
    ${sqlText(lead.phone)},
    ${sqlText(lead.consent)},
    ${sqlTimestamp(lead.consentTimestamp)},
    ${sqlText(legalNoticeVersion)},
    ${sqlText(result.dominantOperational)},
    ${sqlText(result.dominantMotivation)},
    ${sqlText(result.dominantBehavior)},
    ${sqlText(result.lowestBehavior)},
    ${sqlText(result.composite)},
    ${sqlText(result.title)},
    ${sqlText(result.ctaLabel)},
    ${sqlText(result.ctaHref)},
    ${sqlJson(body.answers)},
    ${sqlJson(tracking)},
    ${sqlJson(body)}
  )
  returning id
)
select 200 as status_code, '{"ok":true}'::json as response_body from inserted;
`;

return [{ json: { query } }];
